"use client";

import { useEffect, useMemo, useState } from "react";
import {
  useAccount,
    usePublicClient,
      useWalletClient,
      } from "wagmi";
      import { parseUnits, formatUnits } from "viem";
      import { writeContract, readContract } from "@wagmi/core";

      // ==== CONFIG ====
      const ROUTER_ADDRESS = "0xe3Bb1A8Fca436599A6FA15908e8a01767c565BCc";

      const ROUTER_ABI = [
        {
            name: "getAmountsOut",
                type: "function",
                    stateMutability: "view",
                        inputs: [
                              { name: "amountIn", type: "uint256" },
                                    { name: "path", type: "address[]" },
                                        ],
                                            outputs: [{ name: "amounts", type: "uint256[]" }],
                                              },
                                                {
                                                    name: "swapExactTokensForTokens",
                                                        type: "function",
                                                            stateMutability: "nonpayable",
                                                                inputs: [
                                                                      { name: "amountIn", type: "uint256" },
                                                                            { name: "amountOutMin", type: "uint256" },
                                                                                  { name: "path", type: "address[]" },
                                                                                        { name: "to", type: "address" },
                                                                                              { name: "deadline", type: "uint256" },
                                                                                                  ],
                                                                                                      outputs: [],
                                                                                                        },
                                                                                                        ];

                                                                                                        const ERC20_ABI = [
                                                                                                          {
                                                                                                              name: "approve",
                                                                                                                  type: "function",
                                                                                                                      stateMutability: "nonpayable",
                                                                                                                          inputs: [
                                                                                                                                { name: "spender", type: "address" },
                                                                                                                                      { name: "amount", type: "uint256" },
                                                                                                                                          ],
                                                                                                                                              outputs: [{ type: "bool" }],
                                                                                                                                                },
                                                                                                                                                  {
                                                                                                                                                      name: "decimals",
                                                                                                                                                          type: "function",
                                                                                                                                                              stateMutability: "view",
                                                                                                                                                                  inputs: [],
                                                                                                                                                                      outputs: [{ type: "uint8" }],
                                                                                                                                                                        },
                                                                                                                                                                        ];

                                                                                                                                                                        // Example tokens (replace with your real ones)
                                                                                                                                                                        const TOKENS = [
                                                                                                                                                                          { symbol: "mUSDT", address: "0x22Ce943bEcD4F5Bd27DCc0572CFaf91feB1FDE40", decimals: 18 },
                                                                                                                                                                            { symbol: "mETH", address: "0x336C1a731eef318229E1410518Bc90c5695d312D", decimals: 18 },
                                                                                                                                                                            ];

                                                                                                                                                                            export default function TradePage() {
                                                                                                                                                                              const { address } = useAccount();
                                                                                                                                                                                const publicClient = usePublicClient();

                                                                                                                                                                                  const [tokenIn, setTokenIn] = useState(TOKENS[0]);
                                                                                                                                                                                    const [tokenOut, setTokenOut] = useState(TOKENS[1]);

                                                                                                                                                                                      const [amountIn, setAmountIn] = useState("");
                                                                                                                                                                                        const [amountOut, setAmountOut] = useState("0");

                                                                                                                                                                                          const [slippage, setSlippage] = useState(0.5);
                                                                                                                                                                                            const [loading, setLoading] = useState(false);

                                                                                                                                                                                              const path = useMemo(() => {
                                                                                                                                                                                                  return [tokenIn.address, tokenOut.address];
                                                                                                                                                                                                    }, [tokenIn, tokenOut]);

                                                                                                                                                                                                      // ==== GET PRICE ====
                                                                                                                                                                                                        const getQuote = async () => {
                                                                                                                                                                                                            if (!amountIn || !publicClient) return;

                                                                                                                                                                                                                try {
                                                                                                                                                                                                                      const amountInWei = parseUnits(amountIn, tokenIn.decimals);

                                                                                                                                                                                                                            const res: any = await publicClient.readContract({
                                                                                                                                                                                                                                    address: ROUTER_ADDRESS,
                                                                                                                                                                                                                                            abi: ROUTER_ABI,
                                                                                                                                                                                                                                                    functionName: "getAmountsOut",
                                                                                                                                                                                                                                                            args: [amountInWei, path],
                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                        const out = res[res.length - 1];
                                                                                                                                                                                                                                                                              setAmountOut(formatUnits(out, tokenOut.decimals));
                                                                                                                                                                                                                                                                                  } catch (err) {
                                                                                                                                                                                                                                                                                        console.error("quote error", err);
                                                                                                                                                                                                                                                                                              setAmountOut("0");
                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                    };

                                                                                                                                                                                                                                                                                                      useEffect(() => {
                                                                                                                                                                                                                                                                                                          getQuote();
                                                                                                                                                                                                                                                                                                            }, [amountIn, tokenIn, tokenOut]);

                                                                                                                                                                                                                                                                                                              // ==== APPROVE ====
                                                                                                                                                                                                                                                                                                                const approve = async () => {
                                                                                                                                                                                                                                                                                                                    if (!address) return;

                                                                                                                                                                                                                                                                                                                        const amountInWei = parseUnits(amountIn, tokenIn.decimals);

                                                                                                                                                                                                                                                                                                                            await writeContract({
                                                                                                                                                                                                                                                                                                                                  address: tokenIn.address,
                                                                                                                                                                                                                                                                                                                                        abi: ERC20_ABI,
                                                                                                                                                                                                                                                                                                                                              functionName: "approve",
                                                                                                                                                                                                                                                                                                                                                    args: [ROUTER_ADDRESS, amountInWei],
                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                          };

                                                                                                                                                                                                                                                                                                                                                            // ==== SWAP ====
                                                                                                                                                                                                                                                                                                                                                              const swap = async () => {
                                                                                                                                                                                                                                                                                                                                                                  if (!address) return;

                                                                                                                                                                                                                                                                                                                                                                      setLoading(true);

                                                                                                                                                                                                                                                                                                                                                                          try {
                                                                                                                                                                                                                                                                                                                                                                                const amountInWei = parseUnits(amountIn, tokenIn.decimals);

                                                                                                                                                                                                                                                                                                                                                                                      const res: any = await publicClient.readContract({
                                                                                                                                                                                                                                                                                                                                                                                              address: ROUTER_ADDRESS,
                                                                                                                                                                                                                                                                                                                                                                                                      abi: ROUTER_ABI,
                                                                                                                                                                                                                                                                                                                                                                                                              functionName: "getAmountsOut",
                                                                                                                                                                                                                                                                                                                                                                                                                      args: [amountInWei, path],
                                                                                                                                                                                                                                                                                                                                                                                                                            });

                                                                                                                                                                                                                                                                                                                                                                                                                                  const expectedOut = res[res.length - 1];

                                                                                                                                                                                                                                                                                                                                                                                                                                        const minOut =
                                                                                                                                                                                                                                                                                                                                                                                                                                                (expectedOut * BigInt(100 - slippage * 100)) / 100n;

                                                                                                                                                                                                                                                                                                                                                                                                                                                      const deadline = Math.floor(Date.now() / 1000) + 60 * 10;

                                                                                                                                                                                                                                                                                                                                                                                                                                                            await writeContract({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    address: ROUTER_ADDRESS,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            abi: ROUTER_ABI,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    functionName: "swapExactTokensForTokens",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            args: [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      amountInWei,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                minOut,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          path,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    address,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              BigInt(deadline),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } catch (err) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      console.error("swap error", err);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              setLoading(false);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="w-full max-w-md bg-white p-6 rounded-2xl shadow">

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <h1 className="text-xl font-bold mb-4 text-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              IOPn DEX Trade
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </h1>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* FROM */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <label className="text-sm">From</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <select
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      className="w-full border p-2 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  onChange={(e) =>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                setTokenIn(TOKENS[Number(e.target.value)])
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {TOKENS.map((t, i) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <option key={t.address} value={i}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {t.symbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </select>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="w-full border p-2 mt-2 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      placeholder="0.0"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  value={amountIn}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onChange={(e) => setAmountIn(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* TO */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <label className="text-sm">To</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <select
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="w-full border p-2 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onChange={(e) =>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          setTokenOut(TOKENS[Number(e.target.value)])
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {TOKENS.map((t, i) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <option key={t.address} value={i}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {t.symbol}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </select>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    className="w-full border p-2 mt-2 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                value={amountOut}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            disabled
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* SLIPPAGE */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <label className="text-sm">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    Slippage: {slippage}%
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    type="range"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                min="0.1"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            max="5"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        step="0.1"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    value={slippage}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onChange={(e) =>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              setSlippage(Number(e.target.value))
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      className="w-full"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {/* ACTIONS */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="flex gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onClick={approve}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="w-1/2 bg-gray-200 p-2 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Approve
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                onClick={swap}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            disabled={loading || !address}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        className="w-1/2 bg-blue-600 text-white p-2 rounded"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {loading ? "Swapping..." : "Swap"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {!address && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p className="text-red-500 text-sm mt-3 text-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Connect wallet first
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }